func fetchUser(db *sql.DB, id int) (*User, error) {
	var u User
	err := db.QueryRow("SELECT id, name FROM users WHERE id = $1", id).Scan(&u.ID, &u.Name)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, fmt.Errorf("fetchUser: user %d not found", id)
		}
		return nil, fmt.Errorf("fetchUser: %w", err)
	}
	return &u, nil
}

func fanOut(jobs []string) []string {
	results := make(chan string, len(jobs))
	var wg sync.WaitGroup

	for _, job := range jobs {
		wg.Add(1)
		go func(j string) {
			defer wg.Done()
			results <- process(j)
		}(job)
	}

	wg.Wait()
	close(results)

	out := make([]string, 0, len(jobs))
	for r := range results {
		out = append(out, r)
	}
	return out
}

package main

import "fmt"

// Generic Min — works for any ordered type
func Min[T int | float64 | string](a, b T) T {
	if a < b {
		return a
	}
	return b
}

func main() {
	fmt.Println(Min(3, 7))       // int: 3
	fmt.Println(Min(1.2, 0.8))   // float64: 0.8
	fmt.Println(Min("go", "rust")) // string: go
}

