// stays on stack — does not escape
func stackAlloc() int {
	x := 42
	return x
}

// escapes to heap — address returned
func heapAlloc() *int {
	x := 42
	return &x
}

func main() {
	// go build -gcflags='-m' ./... to verify escape decisions
	fmt.Println(stackAlloc())
	fmt.Println(*heapAlloc())
}

