package main

import (
	"runtime/metrics"
	"time"
	"log"
)

func collectGCMetrics() {
	descs := []metrics.Sample{
		{Name: "/gc/pauses:seconds"},
		{Name: "/memory/classes/heap/objects:bytes"},
		{Name: "/gc/cycles/total:gc-cycles"},
	}
	for range time.Tick(30 * time.Second) {
		metrics.Read(descs)
		log.Printf("heap_objects=%.2fMB gc_cycles=%v",
			float64(descs[1].Value.Uint64())/(1<<20),
			descs[2].Value.Uint64(),
		)
	}
}

func workerPool(ctx context.Context, jobs <-chan Job, n int) {
	var wg sync.WaitGroup
	sem := make(chan struct{}, n)

	for job := range jobs {
		select {
		case sem <- struct{}{}:
		case <-ctx.Done():
			return
		}
		wg.Add(1)
		go func(j Job) {
			defer wg.Done()
			defer func() { <-sem }()
			j.Process()
		}(job)
	}
	wg.Wait()
}
